sp_widget.client_script:
api.controller = function($scope, $timeout, $filter) {

    var c = this;
	//c.loadingTables = true;
    c.searchingTables = false;
    c.records = [];
    c.view = "tables";
    c.selectedTable = null;
    c.pageSelectAll = false;
    c.allSelected = false;
    c.currentPage = 1;
    c.pageSize = 10;
    c.check = sessionStorage.getItem('currentId');
    c.isMigrating = false;
    c.loadingRecords = false;
    c.loadingTables = true;
    c.showSnackbar = false;
    c.snackbarMessage = '';
    c.previewOpen = false;
    c.previewData = {};
    c.tableSearch = '';
    c.recordSearch = '';

    c.inserted = 0;
    c.updated = 0;
    c.total = 0;
    c.count = 0;
    c.conn_name = c.data.instanceName;
    c.url = '';
    c.isCompleted = false;
    c.migrationResult = {};
    c.selected_recs = 0;
    c.showModal = false;
    c.progress = 0;

		//store connection name in session
		sessionStorage.setItem('conn_name', c.conn_name);
    /* ===== TABLE LOADER WATCH ===== */
$scope.$watch(
  function () {
    return c.data.tables;
  },
  function (newVal) {
    if (newVal && newVal.length) {

      // 🔥 tell previous page loader to finish
      sessionStorage.setItem("tablesLoaded", "true");

      $timeout(function () {
        c.loadingTables = false;
      }, 300);
    }
  }
);

    c.availableFilterFields = [
        { key:'number', label:'Number' }
    ];

    c.filters = [{
        field: 'number',
        operator: 'contains',
        value: '',
        logic: 'AND'
    }];

    /* ================= TABLE DISPLAY CONTROL ================= */

 c.searchTimeout = null;

c.getVisibleTables = function() {
    return c.data.tables || [];
};

c.searchTables = function() {

    if (c.searchTimeout) {
        $timeout.cancel(c.searchTimeout);
    }

    c.searchTimeout = $timeout(function() {

        c.searchingTables = true;

        c.server.get({
            action: 'searchTables',
            search: c.tableSearch || ''
        }).then(function(response) {

            c.data.tables = response.data.tables || [];

            c.loadingTables = false;
        });

    }, 300);
};

    /* ================= STATES ================= */

    c.getStateLabel = function(state) {

        var map = {
            "-5": "New",
            "-4": "Assess",
            "-3": "Authorize",
            "-2": "Scheduled",
            "-1": "Implement",
            "0": "Review",
            "1": "New",
            "2": "In Progress",
            "3": "Closed",
            "4": "Canceled",
            "7": "Closed"
        };

        return map[String(state)] || state || "-";
    };

    /* ================= TOAST ================= */

    c.showToast = function(msg) {

        c.snackbarMessage = msg;
        c.showSnackbar = true;

        $timeout(function() {
            c.showSnackbar = false;
        }, 3000);
    };

    /* ================= PREVIEW ================= */

    c.openPreview = function(record) {
        c.previewData = angular.copy(record);
        c.previewOpen = true;
    };

    c.closePreview = function() {
        c.previewOpen = false;
    };

    /* ================= DYNAMIC FILTER FIELDS ================= */

    c.setAvailableFilterFields = function(tableName) {

        var map = {
            incident: [
                { key:'number', label:'Number' },
                { key:'short_description', label:'Description' },
                { key:'sys_updated_by', label:'Updated By' },
                { key:'state', label:'State' }
            ],

            sc_req_item: [
                { key:'number', label:'Number' },
                { key:'short_description', label:'Description' },
                { key:'sys_updated_by', label:'Updated By' },
                { key:'state', label:'State' }
            ],

            change_request: [
                { key:'number', label:'Number' },
                { key:'short_description', label:'Description' },
                { key:'sys_updated_by', label:'Updated By' },
                { key:'state', label:'State' }
            ],

            problem: [
                { key:'number', label:'Number' },
                { key:'short_description', label:'Description' },
                { key:'sys_updated_by', label:'Updated By' },
                { key:'state', label:'State' }
            ],

            task: [
                { key:'number', label:'Number' },
                { key:'short_description', label:'Description' },
                { key:'sys_updated_by', label:'Updated By' },
                { key:'state', label:'State' }
            ],

            sys_user: [
                { key:'name', label:'Name' },
                { key:'user_name', label:'User ID' },
                { key:'sys_updated_by', label:'Updated By' }
            ],

            sys_user_group: [
                { key:'name', label:'Name' },
                { key:'sys_updated_by', label:'Updated By' }
            ],

            cmdb_ci: [
                { key:'name', label:'Name' },
                { key:'sys_updated_by', label:'Updated By' }
            ],

            alm_asset: [
                { key:'asset_tag', label:'Asset Tag' },
                { key:'sys_updated_by', label:'Updated By' }
            ]
        };

        c.availableFilterFields = map[tableName] || [
            { key:'name', label:'Name' },
            { key:'sys_updated_by', label:'Updated By' }
        ];
    };

    /* ================= FILTERS ================= */

    c.addFilter = function(type) {
        c.filters.push({
            field: c.availableFilterFields[0].key,
            operator: 'contains',
            value: '',
            logic: type
        });
    };

    c.removeFilter = function(index) {
        c.filters.splice(index, 1);
    };

    c.dynamicFilter = function(record) {

        var result = true;

        angular.forEach(c.filters, function(f, index) {

            if (!f.value) return;

            var rawVal = f.field === 'state' ? c.getStateLabel(record.state) : record[f.field];
            var val = String(rawVal || '').trim().toLowerCase();
            var target = String(f.value || '').trim().toLowerCase();

            var match = false;

            if (f.operator === 'contains')
                match = val.indexOf(target) !== -1;

            if (f.operator === 'starts')
                match = val.indexOf(target) === 0;

            if (f.operator === 'is')
                match = val === target;

            if (index === 0) {
                result = match;
            } else {
                result = f.logic === 'AND' ? result && match : result || match;
            }

        });

        if (c.filters.every(function(f) {
            return !f.value;
        })) return true;

        return result;
    };

    /* ================= RECORD SEARCH ================= */

    c.recordSearchFilter = function(record) {

        if (!c.recordSearch || !c.recordSearch.trim()) return true;

        var q = c.recordSearch.toLowerCase();

        for (var i = 0; i < c.columns.length; i++) {

            var key = c.columns[i].key;
            var value = record[key];

            if (key === 'state') value = c.getStateLabel(value);

            if (String(value || '').toLowerCase().indexOf(q) !== -1) return true;
        }

        return false;
    };

    $scope.$watch('c.filters', function() {
        c.currentPage = 1;
        c.syncSelectionStates();
    }, true);

    /* ================= OPEN TABLE ================= */

    c.openTable = function(table) {

        c.selectedTable = table;
        c.view = "records";
        c.currentPage = 1;
        c.loadingRecords = true;

        c.setAvailableFilterFields(table.name);

        c.filters = [{
            field: c.availableFilterFields[0].key,
            operator: 'contains',
            value: '',
            logic: 'AND'
        }];

        c.server.get({
            action: "getRecords",
            table: table.name
        }).then(function(response) {

            c.records = response.data.records || [];
            c.setDynamicColumns(c.records);
            c.recordSearch = '';
            if (response.data.totalCount !== undefined) {
                table.count = response.data.totalCount;
            }

            angular.forEach(c.records, function(r) {
                r.selected = false;
            });

            c.loadingRecords = false;
            c.syncSelectionStates();
        });
    };

    c.backToTables = function() {
        c.view = "tables";
        c.records = [];
    };

    /* KEEP REST OF YOUR CURRENT SCRIPT EXACTLY SAME BELOW */



    /* ================= DYNAMIC COLUMNS ================= */

    c.setDynamicColumns = function(records) {

        if (!records || !records.length) return;

        function hasField(field) {
            return records.some(function(r) {
                return r.hasOwnProperty(field);
            });
        }

        c.columns = [];

        var priorityFields = ['name', 'user_name', 'label', 'number'];
        var primaryField = '';

        for (var i = 0; i < priorityFields.length; i++) {
            if (hasField(priorityFields[i])) {
                primaryField = priorityFields[i];
                break;
            }
        }

        if (primaryField) {
            c.columns.push({
                key: primaryField,
                label: primaryField.replace(/_/g, ' ').toUpperCase()
            });
        }

        var columnMap = [
            { key: 'user_name', label: 'USER ID' },
            { key: 'name', label: 'NAME' },
            { key: 'sys_updated_by', label: 'UPDATED BY' },
            { key: 'sys_updated_on', label: 'UPDATED ON' },
            { key: 'state', label: 'STATE' }
        ];

        columnMap.forEach(function(col) {

            var alreadyAdded = c.columns.some(function(cCol) {
                return cCol.key === col.key;
            });

            if (!alreadyAdded && hasField(col.key)) {
                c.columns.push(col);
            }
        });
    };

	c.migrateSelected = function() {

    if (c.isMigrating) return;

    c.isMigrating = true;

    /* =========================
       RESET MODAL STATE
    ========================== */
    c.logs = [];
    c.showModal = true;
    c.progress = 0;
    c.migrationResult = {};
    c.isCompleted = false;
    c.total = c.getSelectedCount();

    var selectedRecordsByTable = {};

    if (c.selectedTable && c.selectedTable.name) {
        selectedRecordsByTable[c.selectedTable.name] = [];

        angular.forEach(c.records, function(r) {
            if (r.selected) {
                selectedRecordsByTable[c.selectedTable.name].push(r);
            }
        });
    }
    c.tableCount = Object.keys(selectedRecordsByTable).length;
    c.logs.push("Starting migration...");

    var progressInterval;
    /* =========================
       FAKE PROGRESS
    ========================== */
    progressInterval = setInterval(function() {

        if (c.progress < 90) {
            c.progress += Math.floor(Math.random() * 5) + 1;
        }

        if (c.progress > 90) {
            c.progress = 90;
        }

        $scope.$applyAsync();

    }, 500);

    c.server.get({
        action: "migrateRecords",
        totalrecs: c.total,
        active_conn: sessionStorage.getItem('currentId'),
        records: Object.keys(selectedRecordsByTable).map(function(table) {
            return {
                name: table,
                records: selectedRecordsByTable[table],
								state: selectedRecordsByTable[table].state
            };
        })
    })

    .then(function(response) {

        clearInterval(progressInterval);
        c.progress = 100;
        c.isMigrating = false;

        if (response.data.success) {

            /* =========================
               SUCCESS STATE
            ========================== */
            c.logs.push("Migration started at " + response.data.sTime);
            c.logs.push("Migration completed at " + response.data.eTime);

            c.isCompleted = true;
            c.conn_name = response.data.instanceName;
            c.inserted = response.data.inserted;
            c.updated = response.data.updated;
					  c.duration = response.data.duration;
            c.url = response.data.instanceUrl;
            c.migrationResult = {
                error: false,
                data: response.data.result
            };

            angular.forEach(c.records, function(r) {
                r.selected = false;
            });

            c.syncSelectionStates();

        } else {

            /* =========================
               FAILURE (SERVER RESPONSE)
            ========================== */
            c.isCompleted = true;
            c.isMigrating = false;

            c.migrationResult = {
                error: true,
                message: response.data.message || "Migration failed"
            };
        }

    })

    .catch(function(error) {

        /* =========================
           ERROR HANDLING (NETWORK / SERVER ERROR)
        ========================== */
        clearInterval(progressInterval);

        c.isMigrating = false;
        c.progress = 0;
        c.isCompleted = true;


        var errMsg = "Unexpected error occurred";

        if (error && error.data && error.data.message) {
            errMsg = error.data.message;
        }

        c.migrationResult = {
            error: true,
            message: errMsg
        };
    });

};



    /* ================= SELECTION ================= */

    c.getSelectedCount = function() {
        return c.records.filter(function(r) { return r.selected; }).length;
    };

    c.toggleCurrentPage = function() {

         var filtered = $filter('filter')($filter('filter')(c.records, c.dynamicFilter), c.recordSearchFilter);
        var start = (c.currentPage - 1) * c.pageSize;
        var end = c.currentPage * c.pageSize;

        var currentPageRecords = filtered.slice(start, end);

        var allChecked = currentPageRecords.length && currentPageRecords.every(function(r) {
            return r.selected;
        });

        angular.forEach(currentPageRecords, function(r) {
            r.selected = !allChecked;
        });

        c.syncSelectionStates();
    };

    c.selectAllRecords = function() {

         var filtered = $filter('filter')($filter('filter')(c.records, c.dynamicFilter), c.recordSearchFilter);

        c.allSelected = !c.allSelected;

        angular.forEach(filtered, function(r) {
            r.selected = c.allSelected;
        });

        c.syncSelectionStates();
    };

    c.syncSelectionStates = function() {

         var filtered = $filter('filter')($filter('filter')(c.records, c.dynamicFilter), c.recordSearchFilter);
        var start = (c.currentPage - 1) * c.pageSize;
        var end = c.currentPage * c.pageSize;

        var current = filtered.slice(start, end);

        c.pageSelectAll = current.length > 0 && current.every(function(r) {
            return r.selected;
        });

        c.allSelected = filtered.length > 0 && filtered.every(function(r) {
            return r.selected;
        });
    };

    /* ================= CART ================= */

    c.addSelectedToCart = function() {

        var cart = JSON.parse(sessionStorage.getItem("migration_cart") || "[]");
        var existingMap = {};

        angular.forEach(cart, function(item) {
            existingMap[item.sys_id] = true;
        });

        var added = 0;
        var skipped = 0;

					angular.forEach(c.records, function(r) {

            if (r.selected) {

                if (!existingMap[r.sys_id]) {
                    cart.push(r);
                    existingMap[r.sys_id] = true;
                    added++;
                } else {
                    skipped++;
                }

                r.selected = false;
            }
        });
        sessionStorage.setItem("migration_cart", JSON.stringify(cart));
        window.dispatchEvent(new Event("cartUpdated"));

        c.syncSelectionStates();

        if (added > 0 && skipped === 0) c.showToast("Added to queue successfully");
        if (added > 0 && skipped > 0) c.showToast(added + " added, " + skipped + " already in queue");
        if (added === 0 && skipped > 0) c.showToast("Selected records already exist in queue");
    };
    c.closeModal = function() {
        c.showModal = false;
    };

    /* ================= PAGINATION ================= */

    c.getTotalPages = function() {
        var filtered = $filter('filter')($filter('filter')(c.records, c.dynamicFilter), c.recordSearchFilter);
        return Math.ceil(filtered.length / c.pageSize) || 1;
    };

    c.nextPage = function() {
        if (c.currentPage < c.getTotalPages()) {
            c.currentPage++;
            c.syncSelectionStates();
        }
    };

    c.prevPage = function() {
        if (c.currentPage > 1) {
            c.currentPage--;
            c.syncSelectionStates();
        }
    };

};

sp_widget.css:
.browse-layout {
  display: flex;
  max-height: calc(100vh - 64px);
position:relative;
  background: linear-gradient(
    to bottom right,
    #ffffff 0%,
    rgba(17, 106, 248, 0.05) 50%,
    rgba(155, 192, 252, 0.10) 100%
  );
}

.not-connected{
	width:100%;
  height:calc(100vh - 64px);
  display:flex;
  flex-direction:column;
  //justify-content:center;
  align-items:center;
}

.global-loader {
  position: fixed;
  inset: 0;
  background: rgba(255,255,255,0.95);

  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;

  z-index: 999999;

  color: #116AF8;
  font-size: 18px;
  font-weight: 600;
}

.global-loader i {
  font-size: 48px;
  margin-bottom: 16px;
}
.dm-sidebar-slot {
  flex-basis: 260px;
  flex-shrink:0;
  height:100%;
}

.browse-wrapper {
  position:relative;
  display: flex;
  flex-direction: column;
  height:100%;
  gap:30px;
  margin: 0 auto;
  overflow-y:auto;
  height:calc(100vh - 64px);
  width: 100%;
  padding: 30px 15%;
}
@media(max-width:1600px){
.browse-wrapper{
  	padding:30px;
  }
}
/* ========================= TABLE CARDS ========================= */

.cards-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
    gap: 20px;
}

.table-card {
    background: #fff;
    border-radius: 18px;
    padding: 22px;
    box-shadow: 0 8px 24px rgba(0, 0, 0, .05);
    transition: all .25s ease;
}

.table-card:hover {
    transform: translateY(-4px);
}

.card-top {
    margin-bottom: 18px;
}

.count {
    font-size: 30px;
    font-weight: 700;
    color: #116AF8;
}

.title {
    font-size: 18px;
    font-weight: 600;
    color: #116AF8;
}

.name {
    font-size: 14px;
    color: #116AF8;
}

.browse-btn {
    width: 100%;
    height: 42px;
    border: none;
    border-radius: 12px;
    background: #116AF8;
    color: white;
    font-weight: 600;
    cursor: pointer;
}
.browse-btn:hover{
   background: linear-gradient(to right, #116AF8, #0A50F5);
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
  transition: all 2s ease-out;
}
/* ========================= HEADER ========================= */

.modern-record-header h1 {
    font-size: 44px;
    font-weight: 700;
    color: #17324d;
    margin-bottom: 10px;
}

.header-badges {
    display: flex;
    gap: 12px;
    margin-bottom: 24px;
}

.badge-table,
.badge-count {
    background: #eef3f9;
    border-radius: 999px;
    padding: 8px 16px;
    font-size: 14px;
}

/* ===== ICON PULSE ANIMATION ===== */
@keyframes zoomPulse {
  0% {
    transform: scale(1) rotate(-10deg);
  }

  50% {
    transform: scale(1.15) rotate(-10deg);
  }

  100% {
    transform: scale(1) rotate(-10deg);
  }
}

.icon-animate {
  animation: zoomPulse 1.6s ease-in-out infinite;
}

/* ========================= SELECTION BAR ========================= */

.selection-bar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    background: #eaf2ff;
    border: 1px solid #9BC0FC;
    border-radius: 18px;
    padding: 20px 26px;
    margin-bottom: 24px;
}

.selection-left {
    display: flex;
    align-items: center;
    gap: 16px;
}

.selection-count {
    width: 46px;
    height: 46px;
    border-radius: 14px;
    background: #116AF8 ;
    color: white;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 700;
}

.browse-header-modern {
    margin-bottom: 28px;
}

.browse-header-modern h1 {
    font-size: 52px;
    font-weight: 700;
    color: #081f4d;
    margin-bottom: 8px;
}

.browse-header-modern p {
    font-size: 28px;
    color: #4d5c74;
}

.browse-header-modern span {
    color: #116AF8;
    font-weight: 600;
}

.table-search-wrapper {
    background: #f7f7f9;
    padding: 28px;
    border-radius: 20px;
    margin-bottom: 32px;
}

.table-search-bar {
    display: flex;
    align-items: center;
    background: #ececef;
    border-radius: 14px;
    padding: 18px 20px;
}

.table-search-bar i {
    font-size: 24px;
    color: #7b8190;
    margin-right: 14px;
}

.table-search-bar input {
    border: none;
    background: transparent;
    width: 100%;
    font-size: 24px;
    outline: none;
}

.selection-sub {
    font-size: 14px;
    color: #556;
}

.selection-actions {
    display: flex;
    gap: 14px;
}

.queue-btn,
.migrate-btn {
    min-width: 160px;
    height: 46px;
    border-radius: 14px;
    border: none;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
}

.queue-btn {
    background: white;
    border: 2px solid #116AF8;
    color: #116AF8;
}

.migrate-btn {
background: #116AF8;
    color: white;
}
.queue-btn:hover{
   background: linear-gradient(to right, #fff, #D3D3D3);
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
  transition: all 2s ease-out;
}
.migrate-btn:hover{
   background: linear-gradient(to right, #116AF8, #0A50F5);
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
  transition: all 2s ease-out;
}

button:disabled {
    opacity: .6;
    cursor: not-allowed;
}

.back-link-modern i.fa-angle-left {
  margin-right: 6px;
}

/* ========================= FILTER BAR ========================= */

.sn-filter-bar {
    background: #f8fbff;
    border-radius: 18px;
    padding: 20px;
    box-shadow: 0 6px 18px rgba(0, 0, 0, .05);
    margin-bottom: 24px;
}

.filter-title {
    font-size: 15px;
    font-weight: 600;
    color: #116AF8;
    display: flex;
    align-items: center;
    gap: 8px;
    margin-bottom: 16px;
}

.filter-list {
    display: flex;
    flex-direction: column;
    gap: 14px;
}

.filter-row {
    display: flex;
    align-items: center;
    gap: 12px;
}

.filter-row select,
.filter-row input {
    height: 42px;
    border: none;
    background: #eef3f9;
    border-radius: 12px;
    padding: 0 14px;
    font-size: 14px;
}

.filter-row select {
    min-width: 150px;
}

.filter-row input {
    min-width: 220px;
}

.logic-line {
    min-width: 60px;
}

.logic-label {
    background: #e8f0fe;
    color: #0A50F5;
    font-size: 12px;
    font-weight: 700;
    padding: 5px 10px;
    border-radius: 999px;
}

.remove-filter-btn {
    border: none;
    background: transparent;
    color: #d9534f;
    font-size: 22px;
    cursor: pointer;
}

.filter-bottom-row {
    margin-top: 18px;
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.filter-actions {
    display: flex;
    gap: 14px;
}

.filter-link-btn {
    border: none;
    background: transparent;
    color: #116AF8 ;
    font-weight: 600;
    cursor: pointer;
}


/* ========================= SELECT ALL BUTTON ========================= */

.select-all-btn {
    min-width: 160px;
    height: 46px;
    border-radius: 14px;
    border: none;
    background: #116AF8;
    color: white;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
}
.select-all-btn:hover{
   background: linear-gradient(to right, #116AF8, #0A50F5);
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
  transition: all 2s ease-out;
}
/* ========================= RECORD GRID ========================= */

.record-header,
.record-row {
    display: grid !important;
    grid-template-columns: 
        50px                /* checkbox */
        repeat(auto-fit, minmax(140px, 1fr)) /* dynamic columns */
        70px;               /* preview always last */

    align-items: center;
    gap: 12px;
    padding: 16px 12px;
    width: 100%;
    box-sizing: border-box;
}

.record-header {
    font-weight: 700;
    color: #17324d;
    border-bottom: 2px solid #dce5f0;
}

.record-row {
    border-bottom: 1px solid #e8edf5;
    background: white;
}

.record-row:hover {
    box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
    transition: all 2s ease-out;
}

.record-header > div,
.record-row > div {
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.rec-id {
    color: #116AF8;
    font-weight: 600;
}

/* ========================= PAGINATION ========================= */

.pagination-bar {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 18px;
    margin-top: 28px;
    padding: 16px 0;
}

.page-btn {
    min-width: 110px;
    height: 44px;
    border: none;
    border-radius: 14px;
    background: #116AF8;
    color: white;
    font-weight: 600;
    cursor: pointer;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    white-space: nowrap;
}

.page-btn:disabled {
    opacity: .5;
    cursor: not-allowed;
}

/* ========================= LOADER ========================= */

.skeleton-wrapper {
    padding: 20px;
}

.skeleton-header {
    height: 44px;
    width: 220px;
    background: #edf2f7;
    border-radius: 12px;
    margin-bottom: 20px;
    animation: pulse 1.2s infinite;
}

.skeleton-row {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 14px;
    margin-bottom: 14px;
}

.sk-cell {
    height: 42px;
    background: #edf2f7;
    border-radius: 10px;
    animation: pulse 1.2s infinite;
}

@keyframes pulse {
    0% { opacity: .5; }
    50% { opacity: 1; }
    100% { opacity: .5; }
}

.state-pill {
    display: inline-block;
    padding: 6px 12px;
    border-radius: 999px;
    background: #eef4fb;
    color: #116AF8;
    font-size: 13px;
    font-weight: 600;
}

/* ========================= SNACKBAR ========================= */

.snackbar {
    position: fixed;
    bottom: 24px;
    right: 24px;
    background: #116AF8;
    color: white;
    padding: 14px 22px;
    border-radius: 12px;
    z-index: 9999;
}

/* ========================= PREVIEW ========================= */

.preview-cell {
    display: flex;
    justify-content: center;
    align-items: center;
}

.preview-icon {
    cursor: pointer;
    font-size: 16px;
    color: #116AF8;
}

.preview-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, .35);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 9999;
}

/* ========================= PREVIEW MODAL ========================= */

.preview-modal {
    width: 700px;
    background: #fff;
    border-radius: 18px;
    padding: 28px;
    box-shadow: 0 20px 60px rgba(0, 0, 0, .2);
    color: #17324d;
}

.preview-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 24px;
}

.preview-header h3 {
    margin: 0;
    font-size: 24px;
    font-weight: 700;
    color: #116AF8;
}

.preview-header button {
    width: 32px;
    height: 32px;
    border: none;
    background: transparent;
    font-size: 22px;
    cursor: pointer;
    border-radius: 50%;
}

.preview-header button:hover {
    background: #f1f5f9;
}

.preview-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 18px 24px;
}

.preview-grid > div {
    display: flex;
    flex-direction: column;
}

.preview-grid label {
    font-size: 13px;
    font-weight: 600;
    color: #556;
    margin-bottom: 6px;
}

.preview-grid div > div {
    font-size: 15px;
    font-weight: 500;
    color: #17324d;
    padding: 6px 10px;
    border-radius: 12px;
    background: #eef3f9;
    overflow-wrap: break-word;
}

.full-width {
    grid-column: span 2;
}

/* ========================= TABLE SEARCH BAR ========================= */

.table-search-bar {
    display: flex;
    align-items: center;
    background: white;
    border-radius: 14px;
    padding: 0 14px;
    height: 52px;
    margin-bottom: 24px;
    box-shadow: 0 6px 18px rgba(0, 0, 0, .05);
    max-width: 420px;
}

.table-search-bar i {
    color: #116AF8;
    font-size: 15px;
    margin-right: 10px;
}

.table-search-bar input {
    border: none;
    outline: none;
    width: 100%;
    font-size: 14px;
    background: transparent;
}
/* ================= SEARCH BAR MODERN ================= */

/* ================= SEARCH AREA EXACT MATCH ================= */

.table-search-wrapper {
    background: #ffffff;
    padding: 28px;
    border-radius: 22px;
    margin-bottom: 24px;
    box-shadow: 0 8px 24px rgba(0,0,0,.05);
    width: 100%;
}

.table-search-bar-modern {
    display: flex;
    align-items: center;
    background: #f3f4f6;
    border: 3px solid #b8b8b8;
    border-radius: 16px;
    height: 60px;
    padding: 0 18px;
    width: 100%;
    box-sizing: border-box;
    box-shadow: none;
    outline: none;
}

.table-search-bar-modern:focus-within {
    border: 3px solid #b8b8b8;
    box-shadow: none;
    outline: none;
}

.table-search-bar-modern i {
    font-size: 24px;
    color: #8b95a7;
    margin-right: 14px;
}

.table-search-bar-modern input {
    border: none;
    outline: none !important;
    box-shadow: none !important;
    width: 100%;
    font-size: 18px;
    background: transparent;
    color: #344054;
}

.table-search-bar-modern input:focus {
    outline: none !important;
    box-shadow: none !important;
    border: none;
}

.table-search-bar-modern input::placeholder {
    color: #667085;
}
/* ================= MODERN MIGRATION MODAL ================= */
.migration-modal-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.55);

  display: flex;
  align-items: center;
  justify-content: center;

  z-index: 99999;
}
.migration-modal.modern {
  width: 520px;
  padding: 40px 30px 30px;
  border-radius: 18px;
  text-align: center;
  position: relative;
  margin:auto;

  /* KEEP YOUR COLOR THEME */
  background: linear-gradient(
    135deg,
    #0A50F5,
    #116AF8
  );

  color: #ffffff;
  box-shadow: 0 30px 80px rgba(0,0,0,0.4);
}

/* CLOSE BUTTON */
.modal-close {
  position: absolute;
  top: 14px;
  right: 18px;
  font-size: 22px;
  cursor: pointer;
  opacity: 0.7;
}
.modal-close:hover {
  opacity: 1;
}



/* TITLE */
.modal-title {
  font-size: 28px;
  font-weight: 700;
  margin-bottom: 6px;
}

.modal-subtitle {
  font-size: 14px;
  opacity: 0.85;
  margin-bottom: 28px;
}

/* STATS */
.modal-stats {
  display: flex;
  gap: 16px;
  justify-content: center;
  margin-bottom: 24px;
}

.stat-box {
  flex: 1;
  background: rgba(255,255,255,0.12);
  padding: 18px;
  border-radius: 14px;
  backdrop-filter: blur(6px);
}

.stat-label {
  font-size: 13px;
  opacity: 0.8;
  margin-bottom: 6px;
}

.stat-value {
  font-size: 24px;
  font-weight: 700;
}

/* PROGRESS BAR */
.modal-progress-bar {
  width: 100%;
  height: 10px;
  background: rgba(255,255,255,0.2);
  border-radius: 10px;
  overflow: hidden;
  margin-bottom: 18px;
}

.modal-progress-fill {
  height: 100%;
  background: #9BC0FC;
  transition: width 0.4s ease;
}

/* FOOTER TEXT */
.modal-footer-text {
  font-size: 12px;
  opacity: 0.75;
}

/* TABLE COUNT */

.table-count-line {
    font-size: 18px;
    color: #4d5c74;
    margin-bottom: 26px;
}
.record-search-wrapper {
  width: 100%;
  margin: 18px 0 16px;
}

.record-search-bar {
  display: flex;
  align-items: center;
  width: 100%;
  background: #ffffff;
  border: 1px solid #dbe3ec;
  border-radius: 14px;
  height: 50px;
  padding: 0 16px;
  box-sizing: border-box;
}

.record-search-bar i {
  font-size: 14px;
  color: #94a3b8;
  margin-right: 12px;
}

.record-search-bar input {
  width: 100%;
  border: none;
  outline: none;
  background: transparent;
  font-size: 14px;
  color: #0f172a;
  box-shadow: none;
}

.record-search-bar input::placeholder {
  color: #94a3b8;
}

.record-search-bar:focus-within {
  border-color: #dbe3ec;
  box-shadow: none;
}

/* ===== SUCCESS MODAL ===== */

.success-modal-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.5);

  display: flex;
  align-items: center;
  justify-content: center;

  z-index: 99999;
}

.success-modal {
  width: 520px;
  padding: 40px 30px;
  border-radius: 16px;
  text-align: center;

  background: linear-gradient(135deg, #cfe8df, #a8d5c3);
  box-shadow: 0 30px 80px rgba(0,0,0,0.3);
  position: relative;
}

/* CLOSE */
.success-close {
  position: absolute;
  top: 14px;
  right: 18px;
  font-size: 20px;
  cursor: pointer;
  opacity: 0.6;
}
.success-close:hover {
  opacity: 1;
}
.failure-backdrop {
  background: rgba(0,0,0,0.65); /* slightly darker for failure */
}

.failure-modal {
  background: linear-gradient(135deg, #f8d7da, #f5b5bb) !important;
}
/* ICON */
.success-icon {
  width: 80px;
  height: 80px;
  background: #16a34a;
  color: white;
  font-size: 36px;

  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;

  margin: 0 auto 20px;
}

/* TEXT */
.success-title {
  font-size: 26px;
  font-weight: 700;
  color: #1e293b;
}

.success-subtitle {
  font-size: 14px;
  color: #475569;
  margin-bottom: 26px;
}

/* CARDS */
.success-stats {
  display: flex;
  gap: 16px;
  margin-bottom: 26px;
}

.success-card {
  flex: 1;
  background: #ffffff;
  border-radius: 14px;
  padding: 18px;
  box-shadow: 0 8px 18px rgba(0,0,0,0.08);
}

.success-card .icon {
  font-size: 20px;
  margin-bottom: 6px;
}

.icon.green { color: #16a34a; }
.icon.dark { color: #334155; }
.icon.purple { color: #7c3aed; }

.success-card .value {
  font-size: 22px;
  font-weight: 700;
}

.success-card .label {
  font-size: 13px;
  color: #64748b;
}

.success-red {
  background: #dc2626 !important;
}
/* ACTIONS */
.success-actions {
  display: flex;
  justify-content: center;
  gap: 12px;
}

.details-btn {
  background: #e5e7eb;
  border: none;
  padding: 10px 16px;
  border-radius: 10px;
  cursor: pointer;
}

.done-btn {
  background: #16a34a;
  color: white;
  border: none;
  padding: 10px 18px;
  border-radius: 10px;
  cursor: pointer;
}

.done-btn:hover {
  background: #15803d;
}

sp_widget.script:
(function () {

	data.side = $sp.getWidget('tracenow_sidebar');

	data.instanceName = '';
	data.instanceUrl = '';
	data.tables = [];
	data.records = [];
	var stats = {
		inserted: 0,
		updated: 0,
		failed: 0,
		details: []
	};

	var migration_logs = [], sTime = 0, eTime = 0, username, password, sourceurl, totalCount, successRate = 0, partial = 0, engine;

	/* =================== GET CONNECTION DETAILS ========= */
	var gr = new GlideRecordSecure('x_sysus_tracenow_connection');
	gr.addQuery('sys_id', $sp.getParameter('sys_id'));
	gr.query();

	if (gr.next()) {
		username = gr.getValue('username');
		password = gr.getValue('password');
		sourceurl = gr.getValue('url');

		data.instanceName = gr.getValue('name');
		data.instanceUrl = sourceurl;
	}


	/* ================= MIGRATE RECORDS ================= */

	if (input && input.action == "migrateRecords") {

		var record_details = {};
		var recordsToMigrate = [];

		(input.records || []).forEach(function(tableGroup) {
			var table = tableGroup.name;

			(tableGroup.records || []).forEach(function(rec) {

				if (rec.sys_id) {

					recordsToMigrate.push({
						table: table,
						sysId: String(rec.sys_id).trim(),
						number: rec.number || '',
						state: rec.state || '',
						short_description: rec.short_description || '',
						migrationStatus: 'pending'
					});
				}

			});

		});


		try {

			/* ============= Check Stats of Tables =========== */

			var existingRecords = {};

			recordsToMigrate.forEach(function(record) {

				var gr = new GlideRecordSecure(record.table);

				if (gr.get(record.sysId)) {
					existingRecords[
						record.table + ':' + record.sysId
					] = true;
				}
			});
			var startTime = new Date().getTime(); // milliseconds
			engine = new DM_MigrationCore();
			var result = engine.migrateMixedRecords(sourceurl, username, password, recordsToMigrate, { sortByTable: true, stopOnError: false });
			if(result) {
				//update number of new inserted record
				recordsToMigrate.forEach(function(rec) {
					var bridge = new global.DM_GlobalNumberBridge();

					var bridgeResult = bridge.restoreNumbers(false, rec.table);
					if(bridgeResult) {
						data.success = true;
					}
					else data.success = false;
				})
			}
			else data.success = false;
			migration_logs = engine.executionLogs;
			migration_logs.push("Migration Completed");
			var endTime = new Date().getTime();

			var durationMs = endTime - startTime;

			var totalSeconds = Math.floor(durationMs / 1000);
			var minutes = Math.floor(totalSeconds / 60);
			var seconds = totalSeconds % 60;

			var durationText = minutes + " min " + seconds + " sec";

			gs.info("Migration Duration: " + durationText);

			data.duration = durationText;
			//check the stats after migration
			var migrationDetails = [];
			recordsToMigrate.forEach(function(record) {

				var key = record.table + ':' + record.sysId;

				var action = existingRecords[key]
				? 'updated'
				: 'inserted';
				migrationDetails.push({
					table: record.table,
					sys_id: record.sysId,
					number: record.number,
					short_description: record.short_description,
					state: record.state,
					status: "success",
					action: action,
					duration: data.duration
				});

				if (action === 'inserted')
					stats.inserted++;
				else
					stats.updated++;

				stats.details.push({
					table: record.table,
					sysId: record.sysId,
					action: action
				});
			});
			data.migrationDetails = migrationDetails;
			data.inserted = stats.inserted;
			data.updated = stats.updated;
			/* Safe success rate */
			if (input.totalrecs > 0) {
				successRate = ((stats.inserted + stats.updated) / input.totalrecs) * 100;
			}

			/* Optional rounding */
			successRate = Math.round(successRate * 100) / 100;
			//store overall migration details 
			var mig = new GlideRecordSecure('x_sysus_tracenow_migration_details');
			mig.initialize();
			mig.setValue('instance_url', sourceurl);
			mig.setValue('records_fetched', input.totalrecs);
			mig.setValue('records_inserted', stats.inserted);
			mig.setValue('records_updated', stats.updated);
			mig.setValue('records_failed', stats.failed);
			mig.setValue('success_rate', successRate);
			mig.setValue('target_instance', gs.getProperty('glide.servlet.uri'));

			var migrationSysId = mig.insert();

			//store record logs in migration logs table
			if (migrationSysId) {

				migrationDetails.forEach(function(rec) {

					var logGr = new GlideRecordSecure(
						'x_sysus_tracenow_tracenow_migration_record_log'
					);

					logGr.initialize();

					logGr.setValue(
						'migration',
						migrationSysId
					);

					logGr.setValue(
						'table',
						rec.table
					);

					logGr.setValue(
						'source_sys_id',
						rec.sys_id
					);

					logGr.setValue(
						'record_number',
						rec.number
					);

					logGr.setValue(
						'status',
						rec.status
					);

					logGr.setValue(
						'action',
						rec.action
					);

					logGr.setValue(
						'duration',
						rec.duration
					);

					logGr.setValue(
						'state',
						rec.state
					);

					logGr.setValue(
						'short_description',
						rec.short_description
					);

					/*
							 * If executionLogs is a single array for the run
							 */
					logGr.setValue(
						'migration_log',
						JSON.stringify(migration_logs || [])
					);

					logGr.insert();
				});
				// Calculate total duration from all record logs

				var totalDurationSeconds = 0;

				var durGR = new GlideRecordSecure(
					'x_sysus_tracenow_tracenow_migration_record_log'
				);

				durGR.addQuery('migration', migrationSysId);
				durGR.query();

				while (durGR.next()) {

					var dur =
							durGR.getValue('duration') || '';

					var minMatch =
							dur.match(/(\d+)\s*min/i);

					var secMatch =
							dur.match(/(\d+)\s*sec/i);

					var mins =
							minMatch ? parseInt(minMatch[1], 10) : 0;

					var secs =
							secMatch ? parseInt(secMatch[1], 10) : 0;

					totalDurationSeconds +=
						(mins * 60) + secs;
				}

				var totalMinutes =
						Math.floor(totalDurationSeconds / 60);

				var remainingSeconds =
						totalDurationSeconds % 60;

				var totalDurationText =
						totalMinutes +
						" min " +
						remainingSeconds +
						" sec";
				//update duration of migration
				var updateMig =
						new GlideRecordSecure(
							'x_sysus_tracenow_migration_details'
						);

				if (updateMig.get(migrationSysId)) {

					updateMig.setValue(
						'duration',
						totalDurationText
					);

					updateMig.update();
				}

			}

		}

		catch (e) {
			data.success = false;
			data.message = "All " + input.totalrecs + " record(s) failed to migrate.";

			var failedMigrations = [];

			for (var i = 0; i < recordsToMigrate.length; i++) {

				var rec = recordsToMigrate[i];

				failedMigrations.push({
					table: rec.table,
					sys_id: rec.sysId,
					number: rec.number,
					short_description: rec.short_description,
					state: rec.state,
					status: "failed",
					action: "failed",
					duration: data.duration || "0 min 0 sec",
					reason: e.message ? e.message : e.toString()
				});
			}

			data.failed = recordsToMigrate.length;
			data.migrationDetails = failedMigrations;

			try {

				var mig_gr = new GlideRecordSecure(
					'x_sysus_tracenow_migration_details'
				);

				mig_gr.initialize();

				mig_gr.setValue('instance_url', sourceurl);
				mig_gr.setValue('records_fetched', input.totalrecs);
				mig_gr.setValue('records_inserted', 0);
				mig_gr.setValue('records_updated', 0);
				mig_gr.setValue('records_failed', recordsToMigrate.length);
				mig_gr.setValue('success_rate', 0);
				mig_gr.setValue('duration', "0 min 0 sec");
				mig_gr.setValue('target_instance', gs.getProperty('glide.servlet.uri'));

				var failedMigrationsysId = mig_gr.insert();


				if (failedMigrationsysId) {

					try {
						failedMigrations.forEach(function(rec) {

							var logGr = new GlideRecordSecure(
								'x_sysus_tracenow_tracenow_migration_record_log'
							);

							logGr.initialize();

							logGr.setValue(
								'migration',
								failedMigrationsysId
							);

							logGr.setValue(
								'table',
								rec.table
							);

							logGr.setValue(
								'source_sys_id',
								rec.sys_id
							);

							logGr.setValue(
								'record_number',
								rec.number
							);

							logGr.setValue(
								'status',
								rec.status
							);

							logGr.setValue(
								'action',
								rec.action
							);

							logGr.setValue(
								'duration',
								rec.duration
							);
							logGr.setValue(
								'reason',
								rec.reason
							);

							logGr.setValue(
								'state',
								rec.state
							);

							logGr.setValue(
								'short_description',
								rec.short_description
							);
							/*
							 * If executionLogs is a single array for the run
							 */
							logGr.setValue(
								'migration_log',
								JSON.stringify(migration_logs || [])
							);

							logGr.insert();

						});
					}

					catch(e) {
						gs.info("Failed to insert into migration logs");
					}

				}

				gs.info(
					'Failed migration record inserted: ' +
					failedMigrationsysId
				);

			} catch (insertEx) {

				gs.error(
					'Failed to insert migration details: ' +
					insertEx
				);
			}
		}

		return;
	}

	/* ================= REST API ================= */

	function callRemote(table, query, limit, getCount) {
		try {

			var r = new sn_ws.RESTMessageV2();
			r.setHttpMethod('get');

			var endpoint = sourceurl +
					"/api/now/table/" + table +
					"?sysparm_query=" + encodeURIComponent(query || '') +
					"&sysparm_limit=" + (limit || 200);

			if (getCount) {
				endpoint += '&sysparm_count=true';
			}

			r.setEndpoint(endpoint);
			r.setBasicAuth(username, password);
			r.setRequestHeader("Accept", "application/json");

			var response = r.execute();
			var body = response.getBody();

			var countHeader = response.getHeader("x-total-count");
			totalCount = parseInt(countHeader, 10) || 0;

			if (getCount) {
				return { count: totalCount };
			}

			return JSON.parse(body);

		} catch (ex) {
			gs.error("REST Error: " + ex);
			return null;
		}
	}

	/* ================= TABLES ================= */

	/* ================= INITIAL TABLE LOAD ================= */

	if (!input) {

		var visibleTables = [
			{name:'incident', label:'Incidents'},
			{name:'change_request', label:'Change Requests'},
			{name:'problem', label:'Problems'},
			{name:'task', label:'Tasks'},
			{name:'cmdb_ci', label:'Configuration Items'},
			{name:'sc_request', label:'Requests'},
			{name:'alm_asset', label:'Assets'}
		];

		for (var i = 0; i < visibleTables.length; i++) {

			callRemote(visibleTables[i].name, '', 1, true);

			data.tables.push({
				name: visibleTables[i].name,
				label: visibleTables[i].label,
				count: totalCount
			});
		}
	}

	/* ================= SEARCH TABLES ================= */

	if (input && input.action == "searchTables") {

		var q = (input.search || '').toLowerCase();

		data.tables = [];

		if (!q) {

			var defaults = [
				{name:'incident', label:'Incidents'},
				{name:'change_request', label:'Change Requests'},
				{name:'problem', label:'Problems'},
				{name:'task', label:'Tasks'},
				{name:'cmdb_ci', label:'Configuration Items'},
				{name:'sc_req_item', label:'Requested Items'},
				{name:'alm_asset', label:'Assets'}
			];

			for (var d = 0; d < defaults.length; d++) {

				callRemote(defaults[d].name, '', 1, true);

				data.tables.push({
					name: defaults[d].name,
					label: defaults[d].label,
					count: totalCount
				});
			}

			return;
		}

		var searchQuery =
				'nameLIKE' + q +
				'^ORlabelLIKE' + q;

		var tables = callRemote(
			'sys_db_object',
			searchQuery,
			50
		);

		if (tables && tables.result) {

			for (var t = 0; t < tables.result.length; t++) {

				var tbl = tables.result[t];

				data.tables.push({
					name: tbl.name,
					label: tbl.label || tbl.name,
					count: null
				});
			}
		}

		return;
	}

	/* ================= RECORDS ================= */

	if (input && input.action === "getRecords") {

		var response = callRemote(input.table, input.query || '', 2000);

		if (response && response.result) {
			response.result.forEach(function(rec) {
				data.records.push({
					sys_id: rec.sys_id,
					number: rec.number,
					state: rec.state,
					name: rec.name,
					label: rec.label,
					user_name: rec.user_name,
					table: rec.sys_class_name || input.table,
					short_description: rec.short_description,
					sys_updated_by: rec.sys_updated_by,
					sys_updated_on: rec.sys_updated_on,
					selected: false
				});
			});
		}

		data.totalCount = totalCount; // ✅ send count lazily
	}

})();
